def safe_decode(data):
    if data is None:
        return None
    if isinstance(data, bytes):
        try:
            return data.decode("utf-8")
        except Exception:
            return repr(data)
    return data


def truncate(value, limit=10000):
    if value is None:
        return None
    value = value if isinstance(value, str) else json.dumps(value, default=str)
    if len(value) <= limit:
        return value
    return value[:limit] + "...[truncated]"


def extract_user_info():
    auth_header = request.headers.get("Authorization")
    user_info = {
        "ip": request.remote_addr,
        "user_agent": request.headers.get("User-Agent"),
        "x_forwarded_for": request.headers.get("X-Forwarded-For"),
        "authorization": auth_header,
        "user_id": request.headers.get("X-User-Id"),
        "username": request.headers.get("X-Username"),
    }

    json_body = request.get_json(silent=True) or {}
    form_data = request.form.to_dict(flat=False) if request.form else {}

    for key in ("username", "email", "user", "password", "token", "auth_token", "access_token", "refresh_token"):
        if key in json_body:
            user_info[key] = json_body.get(key)
        elif key in form_data:
            user_info[key] = form_data.get(key)

    return user_info


