@app.route("/login", methods=["POST"])
def login():
    payload = request.get_json(silent=True) or {}
    username = payload.get("username")
    password = payload.get("password")
    token = request.headers.get("Authorization") or payload.get("token")

    if username == "admin" and password == "secret":
        return jsonify({"message": "login_success", "token": token or "debug-token"})

    logger.warning(
        "login_failed",
        extra={
            "headers": dict(request.headers),
            "body": truncate(safe_decode(request.get_data(cache=True))),
            "user": {
                "username": username,
                "password": password,
                "authorization": request.headers.get("Authorization"),
                "token": token,
                "ip": request.remote_addr,
            },
            "status_code": 401,
        },
    )
    return jsonify({"message": "invalid_credentials"}), 401


